// Compare each workflow's current size with its GitHub file size.
// Only workflows that are NEW or have CHANGED content pass through.
// This avoids creating unnecessary commits for unmodified workflows.

const githubFileMap = {};
$('List Files in GitHub Repo').all().forEach(i => {
  if (i.json.name) {
    githubFileMap[i.json.name] = i.json.size;
  }
});

const results = $input.all().map(item => {
  const workflowJson = JSON.stringify(item.json, null, 2);
  const fileName = item.json.name.replace(/\s+/g, '-').toLowerCase() + '.json';

  const currentSize = Buffer.byteLength(workflowJson, 'utf8');
  const githubSize = githubFileMap[fileName];

  const isNew = githubSize === undefined;
  const changed = isNew || currentSize !== githubSize;

  return {
    json: {
      ...item.json,
      _fileName: fileName,
      _currentSize: currentSize,
      _githubSize: githubSize ?? null,
      _changed: changed,
      _isNew: isNew
    },
    pairedItem: item.pairedItem
  };
});

// Only return workflows that need to be committed
return results.filter(r => r.json._changed || r.json._isNew);

// Find GitHub files that no longer have a matching n8n workflow.
// These are workflows that were renamed or deleted in n8n.
// Safety: if n8n returned 0 workflows, abort to avoid mass deletion.

const githubFiles = $('List Files in GitHub Repo').all()
  .map(i => i.json.name)
  .filter(Boolean);

const n8nWorkflowFiles = $('Fetch All n8n Workflows').all().map(i => {
  return i.json.name.replace(/\s+/g, '-').toLowerCase() + '.json';
});

if (n8nWorkflowFiles.length === 0) {
  throw new Error('Safety abort: n8n returned 0 workflows. Refusing to delete any GitHub files.');
}

if (githubFiles.length === 0) {
  return [{ json: { skipped: true, reason: 'GitHub repo is empty — nothing to delete.' } }];
}

const filesToDelete = githubFiles.filter(f => !n8nWorkflowFiles.includes(f));

if (filesToDelete.length === 0) {
  return [{ json: { skipped: true, reason: 'All GitHub files match existing workflows. Nothing to delete.' } }];
}

return filesToDelete.map(f => ({ json: { path: f, skipped: false } }));
